function solve(sx, sy, x, y) {
    let steps = 0;
    while (x > sx || y > sy) {
        if (x === y) break;

        if (x > y) {
            if (y === 0) break;
            if (y <= 0) break;
            if (x > sx) {
                const k = Math.max(1, Math.floor((x - sx) / y));
                x -= k * y;
                steps += k;
            } else {
                break;
            }
        } else {
            if (x === 0) break;
            if (x <= 0) break;
            if (y > sy) {
                const k = Math.max(1, Math.floor((y - sy) / x));
                y -= k * x;
                steps += k;
            } else {
                break;
            }
        }
    }

    if (x === sx && y === sy) {
        return steps;
    } else {
        return -1;
    }
}
